const SB = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const K = '{{SUPABASE_SERVICE_ROLE_KEY}}';
const SLACK_WH = '{{SLACK_WEBHOOK_URL}}';
const h = { apikey: K, Authorization: 'Bearer ' + K, 'Content-Type': 'application/json' };

const now = new Date();
const weekStart = new Date(now); weekStart.setDate(now.getDate() - 7);
const prevWeekStart = new Date(now); prevWeekStart.setDate(now.getDate() - 14);
const weekStartStr = weekStart.toISOString().split('T')[0];

const agents = await this.helpers.httpRequest({
  method: 'GET',
  url: SB + '/rest/v1/hvac_standard_agent?select=agent_id,company_name,plan_type',
  headers: h, json: true
});

if (!agents || agents.length === 0) {
  return [{ json: { status: 'no_agents' } }];
}

const results = [];

for (const agent of agents) {
  // This week's calls
  const thisCalls = await this.helpers.httpRequest({
    method: 'GET',
    url: SB + '/rest/v1/hvac_call_log' +
      '?agent_id=eq.' + agent.agent_id +
      '&call_timestamp=gte.' + weekStart.toISOString() +
      '&select=call_id,lead_score,is_lead,call_successful,caller_sentiment',
    headers: h, json: true
  });

  // Previous week's calls (for trend)
  const prevCalls = await this.helpers.httpRequest({
    method: 'GET',
    url: SB + '/rest/v1/hvac_call_log' +
      '?agent_id=eq.' + agent.agent_id +
      '&call_timestamp=gte.' + prevWeekStart.toISOString() +
      '&call_timestamp=lt.' + weekStart.toISOString() +
      '&select=call_id',
    headers: h, json: true
  });

  // This week's quality analysis
  const analysis = await this.helpers.httpRequest({
    method: 'GET',
    url: SB + '/rest/v1/transcript_analysis' +
      '?agent_id=eq.' + agent.agent_id +
      '&analysis_date=gte.' + weekStartStr +
      '&select=overall_score,frustration_detected,price_hallucination,confusion_loops,premature_ending',
    headers: h, json: true
  });

  const tc = Array.isArray(thisCalls) ? thisCalls : [];
  const pc = Array.isArray(prevCalls) ? prevCalls : [];
  const ta = Array.isArray(analysis) ? analysis : [];

  const totalThis = tc.length;
  const totalPrev = pc.length;
  const trendPct = totalPrev > 0 ? Math.round(((totalThis - totalPrev) / totalPrev) * 100) : 0;

  // Quality-adjusted health score
  const avgQuality = ta.length > 0 ? ta.reduce((s, a) => s + (a.overall_score || 50), 0) / ta.length : null;
  const leadRate = totalThis > 0 ? tc.filter(c => c.is_lead).length / totalThis : 0;
  const successRate = totalThis > 0 ? tc.filter(c => c.call_successful).length / totalThis : 0;
  const frustrations = ta.filter(a => a.frustration_detected).length;

  let score = avgQuality !== null ? avgQuality : 50;
  score += leadRate * 20;
  score += successRate * 15;
  score -= (frustrations / Math.max(ta.length, 1)) * 20;
  score = Math.max(0, Math.min(100, Math.round(score)));

  try {
    // Delete old entry for this week first (upsert manually)
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: SB + '/rest/v1/client_health_scores?agent_id=eq.' + agent.agent_id + '&week_start=eq.' + weekStartStr,
      headers: h
    });

    await this.helpers.httpRequest({
      method: 'POST',
      url: SB + '/rest/v1/client_health_scores',
      headers: { ...h, Prefer: 'return=minimal' },
      body: {
        agent_id: agent.agent_id,
        company_name: agent.company_name,
        week_start: weekStartStr,
        call_volume_current: totalThis,
        call_volume_previous: totalPrev,
        call_volume_trend: trendPct,
        dashboard_logins: 0,
        payment_status: 'ok',
        health_score: score,
        calculated_at: new Date().toISOString()
      },
      json: true
    });

    results.push({ company: agent.company_name, score, calls: totalThis, trend: trendPct });
  } catch(e) {
    console.error('Health score save failed for ' + agent.company_name + ': ' + e.message);
  }
}

// Slack weekly digest
if (results.length > 0) {
  const avgScore = Math.round(results.reduce((s, r) => s + r.score, 0) / results.length);
  const scoreEmoji = avgScore >= 75 ? '🟢' : avgScore >= 55 ? '🟡' : '🔴';
  const rows = results.sort((a,b) => b.score - a.score)
    .map(r => scoreEmoji + ' *' + r.company + '*: ' + r.score + '/100 | ' + r.calls + ' calls | trend: ' + (r.trend >= 0 ? '+' : '') + r.trend + '%')
    .join('\n');

  await this.helpers.httpRequest({
    method: 'POST', url: SLACK_WH,
    body: {
      text: '📈 Weekly Agent Health Scores',
      blocks: [
        { type: 'header', text: { type: 'plain_text', text: '📈 Weekly Agent Health Report' } },
        { type: 'section', text: { type: 'mrkdwn', text: '*Fleet average: ' + avgScore + '/100*' } },
        { type: 'section', text: { type: 'mrkdwn', text: rows } }
      ]
    },
    json: true
  });
}

return [{ json: { status: 'complete', agents_scored: results.length, results } }];

